+export function parseManifestForIndex(bytes) {
+    // Manifest structure:
+    // - Chunk 1: 4 bytes len + content (index metadata in field 1)
+    // - Chunk 2: 4 bytes len + content (full manifest with schema + fragments)
+    // - Footer (16 bytes)
