+    const over = { partitionBy: [], orderBy: [], frame: null };
+
+    // PARTITION BY clause
+    if (parser.match(TokenType.PARTITION)) {
+        parser.expect(TokenType.BY);
+        over.partitionBy.push(parser.parseExpr());
+        while (parser.match(TokenType.COMMA)) {
+            over.partitionBy.push(parser.parseExpr());
+        }
+    }
